import React, { useState, useEffect } from 'react';
import {
  Box,
  Button,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Grid,
  Card,
  CardContent,
  CardMedia,
  Typography,
  IconButton,
  Chip,
  Alert,
  CircularProgress,
  FormControlLabel,
  Switch
} from '@mui/material';
import { Edit as EditIcon, Delete as DeleteIcon } from '@mui/icons-material';
import { api } from '../../services/api';

const CertificatesManager = () => {
  const [certificates, setCertificates] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingCertificate, setEditingCertificate] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    issuer: '',
    date: '',
    image: '',
    credentialUrl: '',
    skills: [],
    featured: false
  });

  const fetchCertificates = async () => {
    try {
      const response = await api.get('/certificates');
      const data = response.data;
      setCertificates(
        Array.isArray(data)
          ? data
          : data.items || data.data || []
      );
      setError('');
    } catch (err) {
      setError('Failed to fetch certificates');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCertificates();
  }, []);

  const handleOpenDialog = (certificate = null) => {
    if (certificate) {
      setEditingCertificate(certificate);
      setFormData({
        title: certificate.title,
        issuer: certificate.issuer,
        date: certificate.date.split('T')[0],
        image: certificate.image,
        credentialUrl: certificate.credentialUrl,
        skills: certificate.skills,
        featured: certificate.featured
      });
    } else {
      setEditingCertificate(null);
      setFormData({
        title: '',
        issuer: '',
        date: '',
        image: '',
        credentialUrl: '',
        skills: [],
        featured: false
      });
    }
    setDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setDialogOpen(false);
    setEditingCertificate(null);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSkillsChange = (e) => {
    const skills = e.target.value.split(',').map(skill => skill.trim());
    setFormData(prev => ({
      ...prev,
      skills
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingCertificate) {
        await api.patch(`/certificates/${editingCertificate._id}`, formData);
      } else {
        await api.post('/certificates', formData);
      }
      handleCloseDialog();
      fetchCertificates();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save certificate');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this certificate?')) {
      try {
        await api.delete(`/certificates/${id}`);
        fetchCertificates();
      } catch (err) {
        setError('Failed to delete certificate');
      }
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="200px">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      <Box display="flex" justifyContent="flex-end" mb={2}>
        <Button
          variant="contained"
          color="primary"
          onClick={() => handleOpenDialog()}
        >
          Add Certificate
        </Button>
      </Box>

      <Grid container spacing={3}>
        {certificates.map((certificate) => (
          <Grid item xs={12} sm={6} md={4} key={certificate._id}>
            <Card>
              <CardMedia
                component="img"
                height="140"
                image={certificate.image}
                alt={certificate.title}
              />
              <CardContent>
                <Typography variant="h6" gutterBottom>
                  {certificate.title}
                </Typography>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {certificate.issuer}
                </Typography>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {new Date(certificate.date).toLocaleDateString()}
                </Typography>
                <Box mt={1}>
                  {certificate.skills.map((skill, index) => (
                    <Chip
                      key={index}
                      label={skill}
                      size="small"
                      sx={{ mr: 0.5, mb: 0.5 }}
                    />
                  ))}
                </Box>
                <Box mt={2} display="flex" justifyContent="flex-end">
                  <IconButton
                    size="small"
                    onClick={() => handleOpenDialog(certificate)}
                  >
                    <EditIcon />
                  </IconButton>
                  <IconButton
                    size="small"
                    onClick={() => handleDelete(certificate._id)}
                  >
                    <DeleteIcon />
                  </IconButton>
                </Box>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Dialog open={dialogOpen} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
        <DialogTitle>
          {editingCertificate ? 'Edit Certificate' : 'Add Certificate'}
        </DialogTitle>
        <DialogContent>
          <Box component="form" onSubmit={handleSubmit} sx={{ mt: 2 }}>
            <TextField
              fullWidth
              label="Title"
              name="title"
              value={formData.title}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Issuer"
              name="issuer"
              value={formData.issuer}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Date"
              name="date"
              type="date"
              value={formData.date}
              onChange={handleChange}
              margin="normal"
              required
              InputLabelProps={{ shrink: true }}
            />
            <TextField
              fullWidth
              label="Image URL"
              name="image"
              value={formData.image}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Credential URL"
              name="credentialUrl"
              value={formData.credentialUrl}
              onChange={handleChange}
              margin="normal"
              required
            />
            <TextField
              fullWidth
              label="Skills (comma-separated)"
              name="skills"
              value={formData.skills.join(', ')}
              onChange={handleSkillsChange}
              margin="normal"
              required
            />
            <FormControlLabel
              control={
                <Switch
                  checked={formData.featured}
                  onChange={(e) => setFormData(prev => ({
                    ...prev,
                    featured: e.target.checked
                  }))}
                  name="featured"
                />
              }
              label="Featured"
            />
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog}>Cancel</Button>
          <Button onClick={handleSubmit} variant="contained" color="primary">
            {editingCertificate ? 'Update' : 'Add'}
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default CertificatesManager;
